import React, { useState, useEffect } from 'react';
import './App.css';

const API_URL = 'http://localhost/Alert/backendindex.php';

function App() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState('login');

  // Form states
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [error, setError] = useState('');
  const [formLoading, setFormLoading] = useState(false);

  useEffect(() => {
    const token = localStorage.getItem('auth_token');
    const storedUser = localStorage.getItem('user');

    if (token && storedUser) {
      setUser(JSON.parse(storedUser));
      setPage('dashboard');
    }
    setLoading(false);
  }, []);

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    setFormLoading(true);

    try {
      const response = await fetch(`${API_URL}/auth/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password })
      });

      const data = await response.json();

      if (data.success) {
        setUser(data.user);
        localStorage.setItem('auth_token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));
        setPage('dashboard');
      } else {
        setError(data.error || 'Login failed');
      }
    } catch (err) {
      setError('Connection error. Make sure backend is running on http://localhost/weatheralert/');
    } finally {
      setFormLoading(false);
    }
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    setError('');
    setFormLoading(true);

    try {
      const response = await fetch(`${API_URL}/auth/register`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password, name, phone, parish: 'saint-george' })
      });

      const data = await response.json();

      if (data.success) {
        setUser(data.user);
        localStorage.setItem('auth_token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));
        setPage('dashboard');
      } else {
        setError(data.error || 'Registration failed');
      }
    } catch (err) {
      setError('Connection error. Make sure backend is running.');
    } finally {
      setFormLoading(false);
    }
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('auth_token');
    localStorage.removeItem('user');
    setPage('login');
  };

  if (loading) {
    return (
      <div className="loading-screen">
        <div className="spinner"></div>
        <p>Loading WeatherAlert...</p>
      </div>
    );
  }

  // Login Page
  if (page === 'login' && !user) {
    return (
      <div className="auth-container">
        <div className="auth-card">
          <div className="auth-header">
            <div className="logo">🌅</div>
            <h1>WeatherAlert</h1>
            <p>Grenada Weather Monitoring System</p>
          </div>

          <form onSubmit={handleLogin} className="auth-form">
            <h2>Sign In</h2>

            {error && <div className="error-message">{error}</div>}

            <div className="form-group">
              <label>Email</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="your.email@example.com"
                required
              />
            </div>

            <div className="form-group">
              <label>Password</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Enter your password"
                required
              />
            </div>

            <button type="submit" className="btn-primary" disabled={formLoading}>
              {formLoading ? 'Signing in...' : 'Sign In'}
            </button>

            <p className="auth-link">
              Don't have an account? <a href="#" onClick={() => setPage('register')}>Register here</a>
            </p>

            <div className="admin-hint">
              <small>Admin login: shenait0323@gmail.com / WeatherAdmin2024!</small>
            </div>
          </form>
        </div>
      </div>
    );
  }

  // Register Page
  if (page === 'register' && !user) {
    return (
      <div className="auth-container">
        <div className="auth-card">
          <div className="auth-header">
            <div className="logo">🌅</div>
            <h1>WeatherAlert</h1>
            <p>Grenada Weather Monitoring System</p>
          </div>

          <form onSubmit={handleRegister} className="auth-form">
            <h2>Create Account</h2>

            {error && <div className="error-message">{error}</div>}

            <div className="form-group">
              <label>Full Name</label>
              <input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="John Doe"
                required
              />
            </div>

            <div className="form-group">
              <label>Email</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="your.email@example.com"
                required
              />
            </div>

            <div className="form-group">
              <label>Phone (optional)</label>
              <input
                type="tel"
                value={phone}
                onChange={(e) => setPhone(e.target.value)}
                placeholder="+1 473 XXX XXXX"
              />
            </div>

            <div className="form-group">
              <label>Password</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Choose a password"
                required
              />
            </div>

            <button type="submit" className="btn-primary" disabled={formLoading}>
              {formLoading ? 'Creating account...' : 'Register'}
            </button>

            <p className="auth-link">
              Already have an account? <a href="#" onClick={() => setPage('login')}>Sign in here</a>
            </p>
          </form>
        </div>
      </div>
    );
  }

  // Dashboard
  return (
    <div className="dashboard">
      <nav className="navbar">
        <div className="navbar-brand">
          <span className="logo">🌅</span>
          <span>WeatherAlert</span>
        </div>
        <div className="navbar-menu">
          <span style={{color: '#666'}}>Welcome, {user.name}!</span>
          {user.role === 'admin' && <span style={{background: '#667eea', color: 'white', padding: '4px 12px', borderRadius: '6px', fontSize: '12px'}}>ADMIN</span>}
          <button onClick={handleLogout} className="btn-logout">Logout</button>
        </div>
      </nav>

      <div className="container">
        <div className="card">
          <h2>🎉 Welcome to WeatherAlert!</h2>
          <p style={{color: '#666', marginBottom: '20px'}}>
            Your PHP backend + React frontend is working perfectly!
          </p>

          <div style={{background: '#f0f9ff', padding: '20px', borderRadius: '12px', border: '2px solid #0ea5e9'}}>
            <h3 style={{color: '#0369a1', marginBottom: '15px'}}>✅ System Status</h3>
            <ul style={{color: '#075985', lineHeight: '2'}}>
              <li>✓ Backend API connected</li>
              <li>✓ Database connection working</li>
              <li>✓ User authentication functional</li>
              <li>✓ React frontend running</li>
              <li>✓ User role: <strong>{user.role}</strong></li>
              <li>✓ Email: <strong>{user.email}</strong></li>
            </ul>
          </div>

          <div style={{marginTop: '30px', padding: '20px', background: '#fef3c7', borderRadius: '12px'}}>
            <h3 style={{color: '#92400e', marginBottom: '10px'}}>📋 Next Steps:</h3>
            <ol style={{color: '#78350f', lineHeight: '1.8', marginLeft: '20px'}}>
              <li>Add weather API integration (Open-Meteo)</li>
              <li>Build admin panel for alerts</li>
              <li>Add SMS notification system</li>
              <li>Create weather dashboard UI</li>
              <li>Implement automatic alert detection</li>
            </ol>
          </div>
        </div>
      </div>
    </div>
  );
}

export default App;
